var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"침식체들이 폭발 반경 안으로 들어왔습니다! 어쩌죠?","JPN":"侵食体が爆発の半径内に進入しました！　どうしましょう？","ENG":"The C.O.s are within the blast radius, sir! What do we do?","TWN":"侵蝕體已經進入爆炸半徑內！怎麼辦？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"기다려! 아직 대장님이 벗어나지 못했다!","JPN":"待て！　まだ隊長が出ていねえ！","ENG":"Hold! The Captain's still there!","TWN":"先等一下！隊長還沒出來！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"와트. 난 신경 쓰지 말고 기폭장치를 눌러.","JPN":"ワット。私のことは気にせずに起爆装置を押して。","ENG":"Watt, don't mind me. Press the ignition switch.","TWN":"華特，別管我，按下引爆裝置。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"예? 하지만!","JPN":"は？　ですが！","ENG":"What? But...!","TWN":"什麼？可是！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"놈들이 외성을 넘으면 모두가 위험해진다! 어서!","JPN":"やつらが外郭を越えるとみんなが危なくなる！　早く！","ENG":"Everyone will be in danger if they break through the castle wall! Do it now!","TWN":"敵人越過外城的話大家都會有危險！快！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"Y-yes, ma'am!","TWN":"是…遵命！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"하이랜더 타입……. 격퇴 확인.","JPN":"ハイランダータイプ……撃退を確認。","ENG":"Highlander-Type... Kill confirmed.","TWN":"高地闊步者類型……確認擊退。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"대장님의 모습은 확인되지 않습니다.","JPN":"隊長の姿は確認できませんでした。","ENG":"No signs of Captain, sir.","TWN":"無法確認隊長情況。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"다들 예를 갖춰라!","JPN":"みんな、礼をつくせ！","ENG":"Men, atten-hut!","TWN":"所有人行禮！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"엘라 대장님의 명예로운 희생을 기리며…… 경례!","JPN":"エラ隊長の名誉ある犠牲を称え……敬礼！","ENG":"Captain Ella has sacrificed her life for the greater good... Present, arms!","TWN":"紀念艾拉隊長的光榮犧牲……敬禮！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"엣취…!","JPN":"くしゅん……！","ENG":"Ah-choo!","TWN":"哈啾…！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"……재채기?","JPN":"……くしゃみ？","ENG":"A sneeze...?","TWN":"……噴嚏聲？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"훌쩍…","JPN":"スンッ……","ENG":"*Sniffle*","TWN":"噢嗚…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"대장님이다!","JPN":"隊長だ！","ENG":"It’s the Captain!","TWN":"是隊長！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"대장님이 살아 계신다!","JPN":"隊長が生きている！","ENG":"She's alive!","TWN":"隊長還活著！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_03"},{"id":"L31_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"대장님?","JPN":"隊長？","ENG":"Captain?","TWN":"隊長？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그 폭발 속에서 어떻게 살아 나오신 겁니까?","JPN":"あの爆発の中でどうやって生き残ったんですか？","ENG":"How did you survive that explosion?","TWN":"你是怎麼從爆炸中活下來的？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이 녀석의 등을 좀 빌렸다. 꽤 빠르더군.","JPN":"こいつの背中をちょっと借りた。かなり早かったぞ。","ENG":"I had help from this fellow. He's pretty fast.","TWN":"我借用了一下這傢伙的背，它動作還挺快的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORSE_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"우와, 평범한 말은 아닌 것 같은데요? 이거 전부 갑옷이에요?","JPN":"うわ、ただの馬じゃなさそうですね。これ全部鎧なんですか？","ENG":"Whoa... That doesn't look like an ordinary horse. It this all armor?","TWN":"哇，好像不是普通的馬欸？這些全都是盔甲嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"이건…… 왕립군의 병기마잖아?","JPN":"これは……王立軍の兵器馬？","ENG":"This is... It's the Royal Army's Armored Horse!","TWN":"這不是…皇家軍隊的戰馬嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"원작자가 사라진 뒤로 생산이 단절됐다고 들었는데……. 이런 게 왜 국경 밖에서 나타난 거지?","JPN":"開発者が消えてからは生産が中断されたと聞いたが……なんでこんなもんが国境の外に現れたんだ？","ENG":"But I thought manufacturing was discontinued after the original creator passed away... Why is this even outside of the border?","TWN":"我聽說製造的人消失後就停產了…… 它怎麼會出現在國境之外？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"나도 몰라. 이것 좀 싣게 들것이나 가져 와.","JPN":"私にもわからない。これを運ぶ担架を持って来い。","ENG":"Beats me. But bring over a carriage to haul this.","TWN":"我也不知道，拿擔架來裝一下吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"대장님, 그 시체는 뭡니까?","JPN":"隊長、その死体は何ですか？","ENG":"Captain, what's with the body?","TWN":"隊長，那具屍體是怎麼回事？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"말에 태워져 있던 <color=#ffd34c>사람</color>이야.","JPN":"馬に乗せられていた<color=#ffd34c>人間</color>だ。","ENG":"He’s the <color=#ffd34c>human</color> that was riding this horse.","TWN":"他是原本騎在馬上的<color=#ffd34c>人</color>。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"대장님? 이 사람 살아 있는 거 맞아요? 상태가 엄청 나빠 보이는데요?","JPN":"隊長？　この人、本当に生きてるんですか？　状態がだいぶ悪そうですけど。","ENG":"Captain? Is he alive? He doesn't look too good.","TWN":"隊長？這個人確定還活著嗎？他看起來狀態很不好欸？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 숨은 쉬고 있어. 아직 늦지 않았다는 뜻이야.","JPN":"けど、息はある。まだ遅くないってことだ。","ENG":"He's still breathing. That means there still time to treat him.","TWN":"但他還有呼吸，就表示還來得及。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"어서 가서 수술 준비해 줘, 피터.","JPN":"早く行って手術の準備をしろ、ピーター。","ENG":"Get back to the base and prepare for surgery ready, Peter.","TWN":"彼得，快去準備手術。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"Y-yes, ma'am!","TWN":"喔…好！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"꼭 당신이 가야만 하는 건가요?","JPN":"どうしてもあなたが行かないとダメなんですか？","ENG":"Do they really need you to go?","TWN":"非你不可嗎？"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"오랫동안 준비해 온 일이야. 이제 와서 나 혼자 빠질 수는 없어.","JPN":"長い間準備してきたんだ。今更私だけ行かないわけにはいかない。","ENG":"We've been preparing for this for a long time. I can't back out now.","TWN":"這件事已經準備許久，我無法現在才說要退出。"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"돌아오려면… 얼마나 걸릴까요?","JPN":"帰って来るまで……どのくらいかかるんでしょう？","ENG":"When... will you be back home?","TWN":"你這一趟去…多久才會回來？"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"정확한 예정은 없지만, 그리 오래 걸리진 않을 거야.","JPN":"決まった日程はないが、そう長くはかからないはずだ。","ENG":"I don't know for sure, but it won't take long.","TWN":"還不確定，但應該不會太久。"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"부디 무사해야 돼요.","JPN":"どうか無事に帰ってきてください。","ENG":"Please be safe.","TWN":"你一定要平安回來。"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"당신도 부디 무사히 지내고 있어줘.","JPN":"あなたもどうか無事でいてくれ。","ENG":"You too, my love.","TWN":"這段時間你也要照顧好自己。"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"잠깐만요.","JPN":"お待ちください。","ENG":"Wait!","TWN":"等等。"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"떠나기 전에…… 태어날 아이 이름만이라도 지어주고 가요.","JPN":"出発する前に……子供の名前だけでも付けて行ってください。","ENG":"Before you leave... I want you to name our baby.","TWN":"離開之前……先替我肚子裡的寶寶取個名字吧。"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"아직 남자인지 여자인지도 모르잖아.","JPN":"まだ男か女かもわからないじゃないか。","ENG":"We don't even know if it's a boy or a girl yet.","TWN":"都還不知道是男生還女生呢。"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"함께 기다리고 있어 줘. 너무 늦지 않게 돌아올 테니까.","JPN":"一緒に待っていておくれ。あまり遅くならないように頑張るから。","ENG":"Wait for me together. I'll be back as soon as I can.","TWN":"你跟孩子一起等我，我很快就回來。"},"stage":{"bg":"WHITE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"아, 눈 떴네요?","JPN":"お、目を覚ましましたね？","ENG":"Hey, you're awake!","TWN":"喔？你醒啦！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"가망이 희박하다길래 묫자리나 알아보고 있었는데.","JPN":"見込み薄だというから、お墓を探してたんですけど。","ENG":"She said your chances were slim, so I was looking for a good burial spot.","TWN":"原本說你醒過來的機率很渺茫，所以我正在幫你找墓地呢。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_HURT","text":{"KOREA":"여긴 어디지?","JPN":"ここはどこだ？","ENG":"Where am I?","TWN":"這裡是什麼地方？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"우리 마을에서 제일 호화로운 병실이에요. 그래서 정말 위급한 환자들만 데려오죠.","JPN":"この村で一番豪華な病室です。だから本当に急病人だけ連れてくるんですよ。","ENG":"You're in the best hospital room in the village. It's only used for emergency patients.","TWN":"這是我們村裡最豪華的病房，只招待真正病危的患者喔。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_HURT","text":{"KOREA":"네가 날 도와 준 건가? 이거 신세를 졌군.","JPN":"君が私を助けてくれたのか？　これはお世話になったな。","ENG":"Are you the one who helped me? I owe you one, huh?","TWN":"是你救我的嗎？我欠你一個人情。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"나한테는 그런 말 할 필요 없어요.","JPN":"僕にそんなこと言う必要はありませんよ。","ENG":"It's no use thanking me.","TWN":"這話不用對我說。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"침식체한테 쫓기던 당신을 목숨 걸고 구해낸 사람은 제가 아니라 엘라 대장이니까요.","JPN":"侵食体に追われていたあなたを命かけて救い出した人は、僕じゃなくてエラ隊長ですから。","ENG":"The one who saved you from those C.O.s that were chasing after you was Captain Ella.","TWN":"拼命把你從侵蝕體手中救出來的人不是我，而是艾拉隊長。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"그 사람, 수도에서도 보기 힘든 엄청 강한 카운터거든요. 말 타고 나타났을 때는 진짜 멋졌다니까요?","JPN":"隊長は首都でも滅多に見られない凄腕のカウンターなんです。馬に乗って現れた時は本当にカッコよかったんですよ？","ENG":"You see, she's a Counter, and they're hard to come by even in the capital! Man, it was so cool seeing her appear on that horse.","TWN":"她可是在首都也難得一見的超強制裁者，她騎著馬出現的時候真的帥慘。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_HURT","text":{"KOREA":"엘라 대장?","JPN":"エラ隊長？","ENG":"Captain Ella?","TWN":"艾拉隊長？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"네. 우린 그렇게 불러요.","JPN":"はい。僕らはそう呼んでます。","ENG":"Yup. That's what we call her.","TWN":"對，我們都這樣叫她。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"그리고 난 그냥 당신이 병원비도 안 내고 도망칠까 봐 보초를 서는 것뿐이고요.","JPN":"それから僕はただあなたがお金も払わずに逃げるかもしれないから見張ってるだけです。","ENG":"I'm just here guarding the door so that you don't run away without paying your bills first.","TWN":"然後我會在這裡站崗，只是怕你沒付醫藥費就跑掉而已。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_HURT","text":{"KOREA":"괜한 걱정을 끼쳤군. 병원비는 지불하도록 하지.","JPN":"いらぬ心配をかけたな。金は払うとしよう。","ENG":"Sorry for the inconvenience. How much do I owe?","TWN":"真不好意思，讓你如此費心，我會付醫藥費的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"킥킥, 농담이에요. 여기선 돈 있어 봐야 별로 쓸 데도 없고.","JPN":"へへっ、冗談ですよ。ここではお金があっても使えるところもないし。","ENG":"*Chortle* I'm kidding. Plus, money's pretty useless around here.","TWN":"嘻嘻，開玩笑的，在這裡有錢也沒什麼用。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"근데 이름이 뭐예요? 아까부터 묘비명에 뭐라고 적어야 하나 계속 고민했어요.","JPN":"ところで、お名前は？　さっきから墓石になんて書けばいいのかずっと悩んでたんです。","ENG":"But hey, what's your name? I was wondering what to write on the tombstone.","TWN":"話說你叫什麼名字？我剛一直很煩惱，墓碑上到底該寫什麼才好。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_HURT","text":{"KOREA":"묘비명? 그것도 농담 같은 건가?","JPN":"墓石？　それも冗談なのか？","ENG":"Tombstone? Is that also a joke?","TWN":"墓碑？這也是在開玩笑嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"반쯤은 진담이에요. 아저씨, 부상이 너무 심해서 수술 중에 한 세 번은 더 죽었다 깨어났거든요.","JPN":"半分くらいは本気です。おじさん、ひどい怪我のせいで手術中に3回くらいは死んで、やっと目を覚ましたんですからね。","ENG":"Well... kinda? You see, you died on the table about three times due to the severity of your wounds.","TWN":"一半是真的。大叔，你的傷勢太嚴重，在手術時不知道走過鬼門關多少回呢。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"사람끼리 싸울 일도 없는 나라에서 무슨 일을 겪었길래 그런 부상을 당한 거예요?","JPN":"人間同士では戦う理由もない国で、何をしたらそこまで怪我をするんですか？","ENG":"What even happened to you? Those wounds can't be from fighting another person, right?","TWN":"你在這個人與人之間根本沒精力吵架的國家裡，到底是發生什麼事，怎麼會受那麼重的傷？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"엘라 대장이 집도하지 않았으면 아저씬 이미 저세상 사람이었을 거라고요.","JPN":"エラ隊長が執刀してなかったら、おじさんはとっくにあの世に行ってますよ。","ENG":"If Captain Ella didn't operate on you, you'd be 6 feet under already.","TWN":"要不是有艾拉隊長執刀，大叔現在跟我們應該已經是人鬼殊途。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_HURT","text":{"KOREA":"그 엘라 대장이라는 사람이…… 날 구해주고 수술까지 해 준 건가?","JPN":"そのエラ隊長とやらが……私を助けて手術までしてくれたのか？","ENG":"This \\"Captain Ella\\" you keep mentioning... Is she the one who saved my life?","TWN":"是那個叫艾拉隊長的人……救我，還替我進行手術嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_HURT","text":{"KOREA":"……큭!","JPN":"……くっ！","ENG":"...Krrrgh!","TWN":"……咳！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"대장님!","JPN":"隊長！","ENG":"Help!","TWN":"隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CURIAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"살려주십시오, 대장님!","JPN":"助けてください、隊長！","ENG":"Save me, sir!","TWN":"救救我，隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CURIAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"앞이 보이지 않습니다! 너무 어두워요!","JPN":"前が見えません！　真っ暗です！","ENG":"I can't see! It's so dark!","TWN":"我看不到前面！好暗！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CURIAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"큐리안 총사대장님!","JPN":"キュリアン銃士隊長！","ENG":"General Musketeer Curian!!","TWN":"庫里安隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CURIAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"이봐요! 괜찮아요?","JPN":"あの！　大丈夫ですか？","ENG":"Hey! You okay?","TWN":"喂！你沒事吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_HURT","text":{"KOREA":"……그래. 생각났어.","JPN":"……そうだ。思い出した。","ENG":"Yeah... Just thinking.","TWN":"……沒事，我想起來了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_HURT","text":{"KOREA":"제라드 큐리안. 그게 내 이름이다.","JPN":"ジェラード・キュリアン。それが私の名前だ。","ENG":"Gerard Curian. That's my name.","TWN":"傑瑞德· 庫里安，這是我的名字。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"큐리안?","JPN":"キュリアン？","ENG":"Curian?","TWN":"庫里安？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"헤헤, 내가 농담 좀 했다고 바로 복수하는 거예요?","JPN":"へへ、僕が冗談を言ったからってすぐ仕返しですか？","ENG":"He he! Are you getting back at me for my jokes?","TWN":"哈哈，我剛跟你開玩笑，所以你現在要報仇嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"복수? 왜 그런 말을 하지? 이 이름에 무슨 문제라도 있나?","JPN":"仕返し？　なぜだ？　この名前に何か問題でもあるのか？","ENG":"Get back at you? Why would you say that? Is there something wrong with my name?","TWN":"報仇？我為什麼要報仇？這個名字有什麼問題嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"당연히 문제 있죠. 내가 기저귀 차고 다닐 때부터 그 이름은 아무도 안 썼다고요.","JPN":"大ありですよ。僕がオムツをしてた頃から、その名前は誰も使ってません。","ENG":"Well, duh! No one's used that name ever since I was in diapers!","TWN":"當然有問題，打從我穿尿布開始，就沒人會取這個名字。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"국경 밖에서 대체 뭘 하다가 여기 오게 된 거예요? 그런 것도 모르고.","JPN":"国境の外でいったい何をしてここに来ることになったんですか？　そんなことも知らないなんて。","ENG":"Have you been living under a rock all this time outside the border?","TWN":"你在境外到底都在做什麼？竟然連這都不知道。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"미안하군. 지금은 말해줄 수 없어.","JPN":"悪いな。今は話すことができない。","ENG":"Sorry. But I can't tell you that right now.","TWN":"對不起，我現在不能告訴你。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"됐고, 지금은 가만히 있어요. 엘라 대장이 아저씨가 깨어나도 나가게 하지 말랬거든요.","JPN":"まあ、いいから今は大人しくしててくださいよ。エラ隊長から、おじさんが起きても外には出さないようにって言われてますから。","ENG":"Whatever. Just get some rest. Captain Ella told me to keep you in the room even if you woke up.","TWN":"不說就不說，你就乖乖待在這裡。艾拉隊長有交代，你醒起來後以不能讓你出去。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"여기 계속 있을 순 없어. 난 디어루트로 가야만 해.","JPN":"ずっとここにいるわけにはいかない。私はディアルートに向かわなければならないんだ。","ENG":"I can't stay here. I have to go to Deer Root.","TWN":"我不能一直待在這裡，我要去迪魯特。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"디어루트요? 기껏 국경 밖에서 온 양반이 거기로 왜 다시 가려고 하는데요?","JPN":"ディアルート？　せっかく国境の外から来た人が、なんでまたそこに行くんですか？","ENG":"Deer Root? You just made it back and you want to go back out there again?","TWN":"迪魯特？你好不容易才從境外回來，為什麼又要回去那裡？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"난 중요한 임무를 맡은 왕국 군인이다. 폐하께 보고드려야 할 일이 있어.","JPN":"私は重要な任務を与えられた王国の軍人だ。陛下に報告することがある。","ENG":"I am a soldier of the Royal Army on an important mission. I must report back to His Majesty.","TWN":"我是身負重任的皇家軍隊，我有事要稟告陛下。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"폐하?","JPN":"陛下？","ENG":"His Majesty?","TWN":"陛下？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"왕을 말하는 거라면 지금은 없어요.","JPN":"王様のことなら今はいませんよ。","ENG":"If it’s the king you mean, he doesn’t exist anymore.","TWN":"你是指國王嗎？現在沒有國王。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"왕이 없다니? 그게 대체 무슨 소리지?","JPN":"王がいない？　それはどういうことだ？","ENG":"What do you mean there is no king?","TWN":"沒有國王？那是什麼意思？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"아뇨. 말 그대로예요. 마지막 왕은 내가 태어나기도 전에 죽었거든요.","JPN":"いや。言葉どおりです。最後の王様は僕が生まれる前に亡くなりましたから。","ENG":"It means what it means. The last king died way before I was even born.","TWN":"沒有就是沒有，因爲最後一個國王在我出生前就已經駕崩啦。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그렇다면…… 여기는…….","JPN":"なら……ここは……","ENG":"Then... Where am...?","TWN":"那……這裡是……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"여긴 노르드나빅에서도 제일 남쪽에 있는 셔우드 외성이에요.","JPN":"ここはノルドナビックの中でも一番南にあるシャーウッド外郭です。","ENG":"You're at Nordnavik's southernmost outer castle called Sherwood.","TWN":"這裡是諾爾德萊比最南邊的休烏特外城。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"셔우드라면 디어루트보다 한참 북쪽에 있는 곳 아니었나……?","JPN":"シャーウッドならディアルートよりずっと北ではなかったか……？","ENG":"”Sherwood”? But isn't that place far north of Deer Root...?","TWN":"休烏特不是在比迪魯特更北邊的地方嗎……？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"네. 디어루트는 제가 태어나기도 전에 지도에서 지워진 침식지대고요.","JPN":"はい。ディアルートは僕が生まれる前に地図からなくなった侵食地帯です。","ENG":"It is. But Deer Root was wiped off the map after becoming a Corrupted Area ages ago.","TWN":"對，迪魯特是在我出生之前，就已經從地圖上挪去的侵蝕地帶。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그렇군……. 사람들이 살 수 있는 곳이 그렇게나 줄었다는 건가…….","JPN":"そうか……人間が住めるところがそこまで減ったのか……","ENG":"I see... So humanity's settlements have been reduced by that much...","TWN":"原來如此……人類能居住的地方已經變得那麼少嗎……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"듣자 하니, 아무래도 농담을 하고 있는 건 아닌 듯하군.","JPN":"聞いてみれば、どうやら冗談ではないようじゃな。","ENG":"I am beginning to think you're not kidding, are you?","TWN":"聽起來，似乎不像是在開玩笑呢。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"뒤로 물러서라, 피터.","JPN":"下がりなさい、ピーター。","ENG":"Back away, Peter.","TWN":"彼得，你先退下。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"촌장님?","JPN":"村長？","ENG":"Chief?","TWN":"村長？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"왕립 12총사대 중 서열 1위, 총사대장. 제라드 큐리안.","JPN":"王立12銃士隊の中で序列1位、銃士隊長。ジェラード・キュリアン。","ENG":"General Musketeer Gerard Curian, the 1st among 12 Musketeer Divisions of the Royal Army.","TWN":"皇家12射擊隊中排名第一，隊長傑瑞德· 庫里安。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"아무래도 자네가 바로 그 성유물을 훔친 장본인인가 보군.","JPN":"どうやらお前さんがその聖遺物を盗んだ張本人のようじゃな。","ENG":"So it was you who stole the Holy Relic.","TWN":"看來你就是那個盜取聖遺物的罪魁禍首。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"내가…… 성유물을 훔쳤다고?","JPN":"私が……聖遺物を盗んだ？","ENG":"Me... who stole the Holy Relic...?","TWN":"我……盜取聖遺物？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};